import React from "react";
import styled from "styled-components";

const StyledImage = styled.img`
  width: 100%;
  height: 100%;
  object-fit: cover;
  display: block;
  border-radius: 26px;
  border: 1px solid rgba(255, 255, 255, 0.6);
  box-shadow: 0 12px 30px rgba(54, 74, 99, 0.16);
  transition: transform 0.4s ease, box-shadow 0.4s ease;
  @media (max-width: 500px) {
    border-radius: 18px;
    height: auto;
  }
`;

const StyledWrapper = styled.div`
  position: relative;
  width: 380px;
  height: 507px;
  margin: 50px 0 70px 0;
  :before {
    content: "";
    position: absolute;
    inset: 0;
    transform: translate(18px, 18px);
    border: 2px solid rgba(91, 107, 125, 0.45);
    border-radius: 26px;
    z-index: -1;
    transition: transform 0.4s ease;
  }
  :hover:before {
    transform: translate(12px, 12px);
  }
  :hover ${StyledImage} {
    transform: translateY(-6px);
    box-shadow: 0 20px 40px rgba(54, 74, 99, 0.22);
  }
  @media (max-width: 500px) {
    width: 100%;
    max-width: 340px;
    height: auto;
    margin: 0 auto 10px auto;
    :before {
      display: none;
    }
  }
`;

const Image = ({ img, alt }) => (
  <StyledWrapper>
    <StyledImage src={img} alt={alt} />
  </StyledWrapper>
);

export default Image;
